export type ButtonStyle = typeof buttonStyle

import { a11y, page, render } from "#test/browser"
import { LoaderIcon } from "../icon"
import { Button } from "./button"

describe("<Button />", () => {
  test("renders component correctly", async () => {
    await a11y(<Button>test</Button>)
  })

  test("sets `displayName` correctly", () => {
    expect(Button.displayName).toBe("Button")
  })

  test("sets `className` correctly", async () => {
    await render(<Button>test</Button>)

    const button = page.getByText("test")
    await expect.element(button).toHaveClass("ui-button")
  })

  test("renders HTML tag correctly", async () => {
    await render(<Button>test</Button>)

    const button = page.getByText("test")
    expect(button.element().tagName).toBe("BUTTON")
  })

  test("renders with icon", async () => {
    const { rerender } = await render(<Button endIcon={<>end icon</>} />)
    await expect.element(page.getByText("end icon")).toBeInTheDocument()

    await rerender(<Button startIcon={<>start icon</>} />)
    await expect.element(page.getByText("start icon")).toBeInTheDocument()
  })

  test("shows loading text if loading, loadingText and loadingIcon", async () => {
    const { rerender } = await render(
      <Button
        data-testid="btn"
        loading
        loadingIcon={<LoaderIcon data-testid="loadingIcon" />}
        loadingMessage="Submitting"
      >
        Submit
      </Button>,
    )
    await expect
      .element(page.getByTestId("btn"))
      .toHaveAttribute("data-loading", "")

    // children text is hidden
    await expect
      .element(page.getByText(/^Submit$/).query())
      .not.toBeInTheDocument()

    // Submitting" visually hidden label shown
    await expect.element(page.getByText("Submitting")).toBeInTheDocument()

    // Confirm loading position
    await expect
      .element(page.getByTestId("loadingIcon"))
      .toHaveClass("ui-button__loading--start")

    await rerender(
      <Button
        loading
        loadingIcon={<LoaderIcon data-testid="loadingIcon" />}
        loadingMessage="Test if loading placement"
        loadingPlacement="end"
      >
        Submit
      </Button>,
    )

    await expect
      .element(page.getByTestId("loadingIcon"))
      .toHaveClass("ui-button__loading--end")
  })

  test("has the proper aria attributes", async () => {
    const { rerender } = await render(<Button data-testid="btn">Hello</Button>)

    const button = page.getByTestId("btn")

    await expect.element(button).not.toHaveAttribute("data-loading", "")
    await expect.element(button).not.toHaveAttribute("data-active", "")

    // loading sets data-loading=""
    await rerender(
      <Button data-testid="btn" loading>
        Hello
      </Button>,
    )
    await expect
      .element(page.getByTestId("btn"))
      .toHaveAttribute("data-loading", "")

    // active sets data-active=""
    await rerender(
      <Button data-testid="btn" active>
        Hello
      </Button>,
    )
    await expect
      .element(page.getByTestId("btn"))
      .toHaveAttribute("data-active", "")
  })

  test("has the proper type attribute", async () => {
    const { rerender } = await render(<Button data-testid="btn">Submit</Button>)
    await expect
      .element(page.getByTestId("btn"))
      .toHaveAttribute("type", "button")

    await rerender(
      <Button type="submit" data-testid="btn">
        Submit
      </Button>,
    )
    await expect
      .element(page.getByTestId("btn"))
      .toHaveAttribute("type", "submit")

    await rerender(<Button data-testid="btn">Submit</Button>)
    await expect.element(page.getByTestId("btn")).toHaveAttribute("type")
  })

  test("has no the type", async () => {
    await render(
      <Button as="span" data-testid="btn">
        Submit
      </Button>,
    )
    await expect.element(page.getByTestId("btn")).not.toHaveAttribute("type")
  })

  test("should be disabled", async () => {
    const { rerender } = await render(
      <Button data-testid="btn" disabled>
        Invalid Button
      </Button>,
    )
    await expect.element(page.getByRole("button")).toBeDisabled()

    await rerender(
      <Button as="div" data-testid="btn" disabled>
        Invalid Button
      </Button>,
    )

    await expect.element(page.getByTestId("btn")).toHaveAttribute("disabled")
  })
})

"use client"

import type { ElementType, PropsWithChildren, ReactNode } from "react"
import type {
  CSSObject,
  HTMLProps,
  HTMLStyledProps,
  ThemeProps,
} from "@yamada-ui/react"
import type { Loading } from "../loading"
import type { ButtonStyle } from "./button.style"
import {
  Children,
  cloneElement,
  isValidElement,
  useCallback,
  useMemo,
  useRef,
} from "react"
import { createComponent, getClassName, mergeCSS, styled, bem, dataAttr, mergeRefs } from "@yamada-ui/react"
import { getLoadingComponent, isLoadingScheme } from "../loading"
import { Ripple, useRipple } from "../ripple"
import { buttonStyle } from "./button.style"

interface ComponentContext extends Pick<
  ButtonProps,
  "endIcon" | "iconProps" | "loadingIcon" | "loadingMessage" | "startIcon"
> {}

const useButtonType = (value?: ElementType) => {
  const buttonRef = useRef(!value)

  const ref = useCallback((node: HTMLElement | null) => {
    if (node) buttonRef.current = node.tagName === "BUTTON"
  }, [])

  const type = buttonRef.current ? "button" : undefined

  return { ref, type } as const
}

export interface ButtonProps
  extends HTMLStyledProps<"button">, ThemeProps<ButtonStyle> {
  /**
   * If `true`, the button is represented as active.
   *
   * @default false
   */
  active?: boolean
  /**
   * If `true`, the button is disabled.
   *
   * @default false
   */
  disabled?: boolean
  /**
   * If `true`, disable ripple effects when pressing a element.
   *
   * @default false
   */
  disableRipple?: boolean
  /**
   * The icon to display at the end side of the button.
   */
  endIcon?: ReactNode
  /**
   * If `true`, the loading state of the button is represented.
   *
   * @default false
   */
  loading?: boolean
  /**
   * The icon to display when the button is loading.
   *
   * @default 'oval'
   */
  loadingIcon?: Loading.Scheme | ReactNode
  /**
   * The message to display when the button is loading.
   */
  loadingMessage?: ReactNode
  /**
   * The placement of the loading indicator. Accepts `start` or `end`.
   *
   * @default 'start'
   */
  loadingPlacement?: "end" | "start"
  /**
   * The icon to display at the start side of the button.
   */
  startIcon?: ReactNode
  /**
   * The type of button. Accepts `button`, `reset`, or `submit`.
   *
   * @default 'button'
   */
  type?: HTMLProps<"button">["type"]
  /**
   * The props of the icon element.
   */
  iconProps?: ButtonIconProps
  /**
   * The props of the loading icon element.
   */
  loadingProps?: ButtonLoadingProps
}

const {
  component,
  ComponentContext,
  PropsContext: ButtonPropsContext,
  useComponentContext,
  usePropsContext: useButtonPropsContext,
  withContext,
} = createComponent<ButtonProps, ButtonStyle, ComponentContext>(
  "button",
  buttonStyle,
)

export { ButtonPropsContext, useButtonPropsContext }

/**
 * `Button` is an interactive component that allows users to perform actions such as submitting forms and toggling modals.
 *
 * @see https://yamada-ui.com/docs/components/button
 */
export const Button = withContext<"button", ButtonProps>(
  ({
    ref,
    as,
    active,
    children,
    disabled,
    disableRipple,
    endIcon = null,
    loading,
    loadingIcon = "oval",
    loadingMessage,
    loadingPlacement = "start",
    startIcon = null,
    iconProps,
    loadingProps,
    ...rest
  }) => {
    const trulyDisabled = disabled || loading
    const { ref: buttonRef, type } = useButtonType(as)
    const { onClick, ...rippleProps } = useRipple({
      ...rest,
      disabled: disableRipple || trulyDisabled,
    })
    const startLoading = loading && loadingPlacement === "start"
    const endLoading = loading && loadingPlacement === "end"

    const context = useMemo(
      () => ({ endIcon, loadingIcon, loadingMessage, startIcon, iconProps }),
      [loadingIcon, loadingMessage, startIcon, endIcon, iconProps],
    )

    return (
      <ComponentContext value={context}>
        <styled.button
          ref={mergeRefs(ref, buttonRef)}
          as={as}
          type={type}
          data-active={dataAttr(active)}
          data-loading={dataAttr(loading)}
          disabled={trulyDisabled}
          {...rest}
          onClick={onClick}
        >
          {startLoading ? <ButtonStartLoading {...loadingProps} /> : null}

          {loading ? (
            loadingMessage || (
              <styled.span opacity={0}>
                <ButtonContent>{children}</ButtonContent>
              </styled.span>
            )
          ) : (
            <ButtonContent>{children}</ButtonContent>
          )}

          {endLoading ? <ButtonEndLoading {...loadingProps} /> : null}

          <Ripple {...rippleProps} />
        </styled.button>
      </ComponentContext>
    )
  },
)()

const ButtonContent = component<"fragment", PropsWithChildren>(
  ({ children }) => {
    const { endIcon, startIcon, iconProps } = useComponentContext()

    return (
      <>
        {startIcon ? (
          <ButtonStartIcon {...iconProps}>{startIcon}</ButtonStartIcon>
        ) : null}
        {children}
        {endIcon ? (
          <ButtonEndIcon {...iconProps}>{endIcon}</ButtonEndIcon>
        ) : null}
      </>
    )
  },
  { name: "ButtonContent", className: getClassName(bem("button", "content")) },
)()

interface ButtonLoadingProps extends HTMLStyledProps<"svg"> {}

const ButtonLoading = component<"svg", ButtonLoadingProps>(
  (props) => {
    const { loadingIcon, loadingMessage } = useComponentContext()

    const css = useMemo<CSSObject>(
      () => ({
        position: loadingMessage ? "relative" : "absolute",
      }),
      [loadingMessage],
    )

    if (isLoadingScheme(loadingIcon)) {
      const Component = getLoadingComponent(loadingIcon)

      return (
        <Component
          color="currentColor"
          {...props}
          css={mergeCSS(css, props.css)}
        />
      )
    }

    if (isValidElement<HTMLStyledProps<"svg">>(loadingIcon))
      return cloneElement(loadingIcon, {
        ...props,
        ...loadingIcon.props,
        css: mergeCSS(css, props.css, loadingIcon.props.css),
      })

    return null
  },
  { name: "ButtonLoading", className: getClassName(bem("button", "loading")) },
)()

const ButtonStartLoading = component<"svg", ButtonLoadingProps>(ButtonLoading, {
  name: "ButtonStartLoading",
  className: getClassName(bem("button", "loading", "start")),
})()

const ButtonEndLoading = component<"svg", ButtonLoadingProps>(ButtonLoading, {
  name: "ButtonEndLoading",
  className: getClassName(bem("button", "loading", "end")),
})()

interface ButtonIconProps extends HTMLStyledProps<"svg"> {}

const ButtonIcon = component<"svg", ButtonIconProps>(
  ({ children, ...rest }) => {
    if (isValidElement<HTMLProps<"svg">>(children))
      return cloneElement(children, {
        "aria-hidden": true,
        role: "img",
        ...rest,
        ...children.props,
      })

    return Children.count(children) > 1 ? Children.only(null) : null
  },
  { name: "ButtonIcon", className: getClassName(bem("button", "icon")) },
)()

const ButtonStartIcon = component<"svg", ButtonIconProps>(ButtonIcon, {
  name: "ButtonStartIcon",
  className: getClassName(bem("button", "icon", "start")),
})()

const ButtonEndIcon = component<"svg", ButtonIconProps>(ButtonIcon, {
  name: "ButtonEndIcon",
  className: getClassName(bem("button", "icon", "end")),
})()

import { defineComponentStyle } from "@yamada-ui/react"
import { buttonStyle } from "./button.style"

export const iconButtonStyle = defineComponentStyle({
  variants: buttonStyle.variants,

  sizes: {
    "2xs": {
      fontSize: "md",
      minBoxSize: "6",
    },
    xs: {
      fontSize: "lg",
      minBoxSize: "8",
    },
    sm: {
      fontSize: "xl",
      minBoxSize: "9",
    },
    md: {
      fontSize: "2xl",
      minBoxSize: "10",
    },
    lg: {
      fontSize: "3xl",
      minBoxSize: "11",
    },
    xl: {
      fontSize: "4xl",
      minBoxSize: "12",
    },
    "2xl": {
      fontSize: "4xl",
      minBoxSize: "14",
    },
  },

  defaultProps: {
    size: "md",
    variant: "solid",
  },
})

export type IconButtonStyle = typeof iconButtonStyle

import { a11y, page, render } from "#test/browser"
import { BoxIcon } from "../icon"
import { IconButton } from "./icon-button"

describe("<IconButton />", () => {
  test("renders component correctly", async () => {
    await a11y(
      <IconButton
        colorScheme="primary"
        aria-label="Open menu"
        icon={<BoxIcon />}
      />,
    )
  })

  test("sets `displayName` correctly", () => {
    expect(IconButton.displayName).toBe("IconButton")
  })

  test("sets `className` correctly", async () => {
    await render(<IconButton colorScheme="primary" aria-label="Open menu" />)

    await expect.element(page.getByRole("button")).toHaveClass("ui-icon-button")
  })

  test("renders HTML tag correctly", async () => {
    await render(<IconButton colorScheme="primary" aria-label="Open menu" />)

    expect(page.getByRole("button").element().tagName).toBe("BUTTON")
  })

  test("renders children correctly", async () => {
    await render(
      <IconButton colorScheme="primary" aria-label="Open menu">
        <BoxIcon data-testid="icon" />
      </IconButton>,
    )

    await expect.element(page.getByTestId("icon")).toBeInTheDocument()
  })
})
